1	import { describe, it, expect } from "vitest";
2	import { scale } from "./pixel-art-scaler.js";
3	
4	describe("Pixel Art Scaler", () => {
5	  it("should return empty output for empty image with any scale", () => {
6	    expect(scale([], 1)).toEqual([]);
7	    expect(scale([], 5)).toEqual([]);
8	  });
9	  it("should return identical copy when scale is 1", () => {
10	    expect(scale(["@"], 1)).toEqual(["@"]);
11	  });
12	  it("should return 4x4 grid of @ for single pixel @ with scale 4", () => {
13	    expect(scale(["@"], 4)).toEqual(["@@@@", "@@@@", "@@@@", "@@@@"]);
14	  });
15	  it("should return 3 rows of AAABBBCCC for single row ABC with scale 3", () => {
16	    expect(scale(["ABC"], 3)).toEqual(["AAABBBCCC", "AAABBBCCC", "AAABBBCCC"]);
17	  });
18	  it("should return [XX, XX, YY, YY, ZZ, ZZ] for single column [X, Y, Z] with scale 2", () => {
19	    expect(scale(["X", "Y", "Z"], 2)).toEqual(["XX", "XX", "YY", "YY", "ZZ", "ZZ"]);
20	  });
21	  it("should return [##.., ##.., ..##, ..##] for 2x2 input [#., .#] with scale 2", () => {
22	    expect(scale(["#.", ".#"], 2)).toEqual(["##..", "##..", "..##", "..##"]);
23	  });
24	  it.todo("should scale 3x3 complex pattern with scale 2");
25	});
26

1	export function scale(image: string[], factor: number): string[] {
2	  return image.flatMap((row) => repeat(scaleRow(row, factor), factor));
3	}
4	
5	function scaleRow(row: string, factor: number): string {
6	  return row
7	    .split("")
8	    .map((char) => char.repeat(factor))
9	    .join("");
10	}
11	
12	function repeat<T>(value: T, times: number): T[] {
13	  return Array(times).fill(value);
14	}
